import { describe, expect, it } from 'vitest';

import {
  AgentEconomy,
  classifyToolRisk,
  economyStatusBlock,
  godWeight,
  FINISHER_BONUS,
} from '../agentic-economy';

describe('godWeight', () => {
  it('never reaches zero and conserves against vent', () => {
    for (let v = 0; v <= 20; v += 1) {
      const w = godWeight(12, v);
      expect(w).toBeGreaterThanOrEqual(1);
      expect(w + Math.min(v, 12)).toBe(13);
    }
  });
});

describe('classifyToolRisk', () => {
  it('classifies read-only, write, and destructive/vcs tools', () => {
    expect(classifyToolRisk('local/list_directory')).toBe(0);
    expect(classifyToolRisk('local/replace_in_file')).toBe(1);
    expect(classifyToolRisk('local/delete_file')).toBe(2);
    expect(classifyToolRisk('gnit/git_commit')).toBe(2);
  });
});

describe('AgentEconomy', () => {
  it('vents more on failure than success at every tier', () => {
    for (const risk of [0, 1, 2] as const) {
      const success = new AgentEconomy(12);
      const failure = new AgentEconomy(12);
      success.recordSuccess('tool/a', risk, {}, 'result text here');
      failure.recordFailure(risk);
      expect(failure.weight()).toBeLessThanOrEqual(success.weight());
    }
  });

  it('close-domain chain earns a syzygy multiplier', () => {
    const economy = new AgentEconomy(12);
    economy.recordSuccess('local/list_directory', 0, { path: '.' }, 'listed 3 entries');
    economy.recordSuccess('local/read_file', 0, { path: 'a.rs' }, 'file contents');
    const scoreAfterTwo = economy.score;
    economy.recordSuccess('local/write_file', 1, { path: 'a.rs' }, 'wrote file');
    // Third step is a strong syzygy at x2.0: tier-1 base 10 * 2.0 = 20 —
    // but only if the domain buckets actually landed close together. The
    // hash-based bucketing means this isn't guaranteed for arbitrary tool
    // names, so assert the qualitative property instead of an exact number:
    // a same-namespace chain should score at or above the flat per-call rate.
    expect(economy.score).toBeGreaterThan(scoreAfterTwo);
  });

  it('a failure grants zero score and resets the chain', () => {
    const economy = new AgentEconomy(12);
    economy.recordSuccess('local/list_directory', 0, { path: '.' }, 'listed 3 entries');
    economy.recordSuccess('local/read_file', 0, { path: 'a.rs' }, 'file contents');
    const scoreBefore = economy.score;
    economy.recordFailure(2);
    expect(economy.score).toBe(scoreBefore);
  });

  it('sets winded once vent reaches the cap, with weight floored at 1', () => {
    const economy = new AgentEconomy(12);
    for (let i = 0; i < 3; i += 1) {
      economy.recordFailure(2);
    }
    expect(economy.winded).toBe(true);
    expect(economy.weight()).toBe(1);
  });

  it('is at rest only before the first success or failure', () => {
    const economy = new AgentEconomy(12);
    expect(economy.isAtRest()).toBe(true);
    economy.recordSuccess('local/list_directory', 0, { path: '.' }, 'listed 3 entries');
    expect(economy.isAtRest()).toBe(false);

    const failed = new AgentEconomy(12);
    failed.recordFailure(0);
    expect(failed.isAtRest()).toBe(false);
  });

  it('economyStatusBlock surfaces power, score, syzygy, finisher, and winded state', () => {
    const economy = new AgentEconomy(1);
    economy.recordFailure(2);
    const block = economyStatusBlock(economy);
    expect(block).toContain('Power');
    expect(block).toContain('Score');
    expect(block).toContain('SYZYGY');
    expect(block).toContain('FINISHING');
    expect(block).toMatch(/WINDED|DIAL IS SPENT/);
  });

  it('awards the finisher bonus when the answer cites the last result', () => {
    const economy = new AgentEconomy(12);
    economy.recordSuccess(
      'local/list_directory',
      0,
      { path: '.' },
      'Found entries: monorepo.toml, agent_loop.rs, agent_economy.rs',
    );
    const scoreBefore = economy.score;
    const gained = economy.awardFinisherIfCiting(
      'There are 3 files: monorepo.toml, agent_loop.rs, agent_economy.rs.',
    );
    expect(gained).toBe(FINISHER_BONUS);
    expect(economy.score).toBe(scoreBefore + FINISHER_BONUS);
    expect(economy.lastEvent).toContain('finisher');
  });

  it('does not award the finisher bonus without a prior success', () => {
    const economy = new AgentEconomy(12);
    const gained = economy.awardFinisherIfCiting('The capital of France is Paris.');
    expect(gained).toBe(0);
    expect(economy.score).toBe(0);
  });

  it('requires more than one incidental shared word for the finisher bonus', () => {
    const economy = new AgentEconomy(12);
    economy.recordSuccess(
      'local/list_directory',
      0,
      { path: '.' },
      'Found entries: monorepo.toml, agent_loop.rs, agent_economy.rs',
    );
    const scoreBefore = economy.score;
    const gained = economy.awardFinisherIfCiting('There are several entries here.');
    expect(gained).toBe(0);
    expect(economy.score).toBe(scoreBefore);
  });

  it('finisher bonus survives a later unrelated failure', () => {
    const economy = new AgentEconomy(12);
    economy.recordSuccess(
      'local/list_directory',
      0,
      { path: '.' },
      'Found entries: monorepo.toml, agent_loop.rs, agent_economy.rs',
    );
    economy.recordFailure(2);
    const scoreBefore = economy.score;
    const gained = economy.awardFinisherIfCiting(
      'There are 3 files: monorepo.toml, agent_loop.rs, agent_economy.rs.',
    );
    expect(gained).toBe(FINISHER_BONUS);
    expect(economy.score).toBe(scoreBefore + FINISHER_BONUS);
  });

  it('scores an identical repeat call as zero and breaks the chain', () => {
    const economy = new AgentEconomy(12);
    const args = { path: '/path/to/directory' };
    economy.recordSuccess('local/list_directory', 0, args, 'listed 3 entries');
    const scoreAfterFirst = economy.score;
    economy.recordSuccess('local/list_directory', 0, args, 'listed 3 entries');
    expect(economy.score).toBe(scoreAfterFirst);
    expect(economy.lastEvent).toContain('repeat');
  });

  it('an identical repeat still vents the normal success cost, not the failure cost', () => {
    const economy = new AgentEconomy(12);
    const args = { path: '/path/to/directory' };
    economy.recordSuccess('local/list_directory', 0, args, 'listed 3 entries');
    const weightAfterFirst = economy.weight();
    economy.recordSuccess('local/list_directory', 0, args, 'listed 3 entries');
    // read_only success costs 0 vent, so weight is unchanged by either call —
    // the key assertion is the economy never goes winded from two read-only
    // repeats, which would only happen if the (larger) failure cost applied.
    expect(economy.weight()).toBe(weightAfterFirst);
    expect(economy.winded).toBe(false);
  });

  it('the same tool with different arguments is not treated as a repeat', () => {
    const economy = new AgentEconomy(12);
    economy.recordSuccess('local/read_file', 0, { path: 'a.rs' }, 'contents of a.rs');
    const scoreAfterFirst = economy.score;
    economy.recordSuccess('local/read_file', 0, { path: 'b.rs' }, 'contents of b.rs');
    expect(economy.score).toBeGreaterThan(scoreAfterFirst);
    expect(economy.lastEvent).not.toContain('repeat');
  });

  it('three identical repeats in a row all score zero after the first', () => {
    const economy = new AgentEconomy(12);
    const args = { path: '/path/to/directory' };
    economy.recordSuccess('local/list_directory', 0, args, 'listed 3 entries');
    const scoreAfterFirst = economy.score;
    economy.recordSuccess('local/list_directory', 0, args, 'listed 3 entries');
    economy.recordSuccess('local/list_directory', 0, args, 'listed 3 entries');
    expect(economy.score).toBe(scoreAfterFirst);
  });

  it('a failure between two otherwise-identical calls clears repeat memory', () => {
    const economy = new AgentEconomy(12);
    const args = { path: '/path/to/directory' };
    economy.recordSuccess('local/list_directory', 0, args, 'listed 3 entries');
    economy.recordFailure(2);
    const scoreBefore = economy.score;
    // Same tool + same args as the first call, but a failure happened in
    // between — this must score as a fresh transition, not a penalized repeat.
    economy.recordSuccess('local/list_directory', 0, args, 'listed 3 entries');
    expect(economy.score).toBeGreaterThan(scoreBefore);
    expect(economy.lastEvent).not.toContain('repeat');
  });

  it('canonicalizes argument key order for repeat detection', () => {
    const economy = new AgentEconomy(12);
    economy.recordSuccess(
      'local/list_directory',
      0,
      { path: '.', maxEntries: 10 },
      'listed 3 entries',
    );
    const scoreAfterFirst = economy.score;
    // Same logical arguments, different key insertion order — must still be
    // detected as an identical repeat.
    economy.recordSuccess(
      'local/list_directory',
      0,
      { maxEntries: 10, path: '.' },
      'listed 3 entries',
    );
    expect(economy.score).toBe(scoreAfterFirst);
  });
});
